    };
}

class Scripts {
    String test;
    String viewSupported;

    Scripts({
        required this.test,
        required this.viewSupported,
    });

    factory Scripts.fromJson(Map<String, dynamic> json) => Scripts(
        test: json["test"],
        viewSupported: json["view-supported"],
    );

    Map<String, dynamic> toJson() => {
        "test": test,
        "view-supported": viewSupported,
    };
}
